def train_epoch(model, X, y, opt, loss_fn):
    model.train()
    opt.zero_grad()
    y_hat = model(X)
    loss = loss_fn(y_hat, y)   # needs labels
    loss.backward()
    opt.step()
    return loss.item()

def infer(model, X_new):
    model.eval()
    with torch.no_grad():        # no gradients, no label y
        return model(X_new)
